-- Synthetic RTU-style B.Tech dataset
CREATE TABLE branches(id SERIAL PRIMARY KEY,name TEXT);
CREATE TABLE teachers(id SERIAL PRIMARY KEY,name TEXT,branch TEXT,email TEXT);
CREATE TABLE subjects(id SERIAL PRIMARY KEY,branch TEXT,name TEXT);
CREATE TABLE students(id SERIAL PRIMARY KEY,enrollment_no TEXT,name TEXT,branch TEXT,semester INT,dob DATE,email TEXT,cgpa NUMERIC(3,2),password TEXT);
CREATE TABLE teacher_subjects(teacher_id INT, subject_id INT);
